def caesar_cipher(text: str, shift: int) -> str:
    result = []

    for char in text:
        if 'a' <= char <= 'z':
            # Handle lowercase letters
            base = ord('a')
            shifted = (ord(char) - base + shift) % 26
            result.append(chr(base + shifted))
        elif 'A' <= char <= 'Z':
            # Handle uppercase letters
            base = ord('A')
            shifted = (ord(char) - base + shift) % 26
            result.append(chr(base + shifted))
        else:
            # Leave non-alphabetic characters unchanged
            result.append(char)

    return ''.join(result)
