import re

def word_frequency(text: str) -> dict[str, int]:
    if not text:
        return {}

    # Split on whitespace
    words = text.split()

    # Process each word: strip punctuation and convert to lowercase
    processed_words = []
    for word in words:
        # Remove punctuation from both ends and convert to lowercase
        cleaned_word = re.sub(r'^\W+|\W+$', '', word).lower()
        if cleaned_word:  # Only add non-empty words
            processed_words.append(cleaned_word)

    # Count frequencies
    frequency = {}
    for word in processed_words:
        frequency[word] = frequency.get(word, 0) + 1

    return frequency
